import React, { useState, useEffect, useMemo, useCallback } from "react";
import { Eye, Building, Home } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { DataTable } from "../../components/ui/DataTable";
import { Button } from "../../components/common/Button";
import { PageHeader } from "../../components/common/PageHeader";
import { getApplications } from "../../services/admin.service";
import { formatDateISTNoTime } from "../../utils/date";
import {
  getPosts,
  getDistricts,
  getApplicationStatuses,
} from "../../services/master.service";
import toast from "react-hot-toast";

const statusColors = {
  DRAFT: "bg-gray-100 text-gray-700",
  SUBMITTED: "bg-blue-100 text-blue-700",
  UNDER_REVIEW: "bg-yellow-100 text-yellow-700",
  ELIGIBLE: "bg-green-100 text-green-700",
  NOT_ELIGIBLE: "bg-red-100 text-red-700",
  ON_HOLD: "bg-amber-100 text-amber-700",
  DOCUMENT_PENDING: "bg-orange-100 text-orange-700",
  REJECTED: "bg-red-200 text-red-800",
  SELECTED: "bg-emerald-100 text-emerald-700",
  WAITLISTED: "bg-purple-100 text-purple-700",
};

const ApplicationList = () => {
  const navigate = useNavigate();
  const [applications, setApplications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  const [filters, setFilters] = useState({
    status: "",
    post_id: "",
    district_id: "",
  });

  const [posts, setPosts] = useState([]);
  const [districts, setDistricts] = useState([]);
  const [statuses, setStatuses] = useState([]);

  useEffect(() => {
    const loadMasters = async () => {
      try {
        const [postsRes, districtsRes, statusesRes] = await Promise.all([
          getPosts({ is_active: true }),
          getDistricts({ is_active: true }),
          getApplicationStatuses({ is_active: true }),
        ]);
        setPosts(Array.isArray(postsRes) ? postsRes : postsRes.posts || []);
        setDistricts(
          Array.isArray(districtsRes)
            ? districtsRes
            : districtsRes.districts || []
        );
        setStatuses(
          Array.isArray(statusesRes) ? statusesRes : statusesRes.statuses || []
        );
      } catch (err) {
        console.error("Failed to load masters", err);
      }
    };
    loadMasters();
  }, []);

  const fetchApplications = useCallback(async () => {
    setLoading(true);
    try {
      const params = {
        page,
        limit,
        search: searchQuery,
        ...Object.fromEntries(
          Object.entries(filters).filter(([_, v]) => v !== "")
        ),
      };
      const response = await getApplications(params);
      setApplications(response.applications || []);
      setTotalPages(response.pagination?.totalPages || 1);
      setTotalItems(response.pagination?.total ?? response.pagination?.totalItems ?? 0);
    } catch (err) {
      toast.error(err.message || "Failed to load applications");
    } finally {
      setLoading(false);
    }
  }, [page, limit, searchQuery, filters]);

  useEffect(() => {
    fetchApplications();
  }, [fetchApplications]);

  const columns = useMemo(
    () => [
      { key: "application_no", header: "Application No", sortable: true },
      {
        key: "applicant",
        header: "Applicant",
        render: (_, row = {}) => row.applicant?.personal?.full_name || row.applicant?.full_name || "-",
      },
      { key: "post", header: "Post", render: (_, row = {}) => row.post?.post_name || "-" },
      {
        key: "hub",
        header: "Hub",
        className: "text-center",
        render: (_, row = {}) => {
          const hubName = row.post?.hub?.hub_name;
          if (!hubName) return "-";
          
          return (
            <div className="flex justify-center">
              <div 
                className="relative group cursor-pointer"
                title={hubName}
              >
                <Home className="h-4 w-4 text-blue-600" />
                <div className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-2 px-2 py-1 bg-gray-800 text-white text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap z-10">
                  {hubName}
                  <div className="absolute top-full left-1/2 transform -translate-x-1/2 -mt-1 w-0 h-0 border-l-4 border-r-4 border-t-4 border-transparent border-t-gray-800"></div>
                </div>
              </div>
            </div>
          );
        },
      },
      {
        key: "osc",
        header: "OSC",
        className: "text-center", 
        render: (_, row = {}) => {
          const componentName = row.post?.component?.component_name;
          if (!componentName) return "-";
          
          return (
            <div className="flex justify-center">
              <div 
                className="relative group cursor-pointer"
                title={componentName}
              >
                <Building className="h-4 w-4 text-green-600" />
                <div className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-2 px-2 py-1 bg-gray-800 text-white text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap z-10">
                  {componentName}
                  <div className="absolute top-full left-1/2 transform -translate-x-1/2 -mt-1 w-0 h-0 border-l-4 border-r-4 border-t-4 border-transparent border-t-gray-800"></div>
                </div>
              </div>
            </div>
          );
        },
      },
      {
        key: "post_district",
        header: "Post District",
        render: (_, row = {}) => row.district?.district_name || "-",
      },
      {
        key: "personal_district",
        header: "Personal District",
        render: (_, row = {}) => row.applicant?.address?.permanentDistrict?.district_name || "-",
      },
      {
        key: "status",
        header: "Status",
        className: "text-center",
        render: (_, row = {}) => (
          <span
            className={`inline-flex rounded-full px-2 py-1 text-xs font-medium ${statusColors[row.status] || "bg-gray-100"}`}
          >
            {row.status?.replace(/_/g, " ")}
          </span>
        ),
      },
      {
        key: "submitted_at",
        header: "Submitted",
        render: (_, row = {}) => formatDateISTNoTime(row.submitted_at),
      },
      {
        key: "actions",
        header: "Actions",
        className: "text-center",
        render: (_value, row = {}) => (
          <div className="flex justify-center">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => row.application_id && navigate(`/applications/${row.application_id}`)}
              className="text-blue-600 hover:text-blue-900"
            >
              <Eye className="h-4 w-4" />
            </Button>
          </div>
        ),
      },
    ],
    [navigate]
  );

  return (
    <div className="space-y-6">
      <PageHeader
        title="Applications"
        description="Review and manage applications"
      />

      <DataTable
        columns={columns}
        data={applications}
        onSearch={setSearchQuery}
        pagination={{
          currentPage: page,
          totalPages,
          totalItems,
          onPageChange: setPage,
          pageSize: limit,
          onPageSizeChange: (newLimit) => {
            setLimit(newLimit);
            setPage(1);
          },
          pageSizeOptions: [10, 20, 50],
        }}
        isLoading={loading}
        rowKey="application_id"
        headerClassName="bg-slate-900 text-white"
        showRowNumbers={true}
      />
    </div>
  );
};

export default ApplicationList;